#include <gtest/gtest.h>
#include "Vrv32i_decoder.h"  // Generated by Verilator

// Test fixture for Decoder with Verilator
class DecoderTestVerilator : public ::testing::Test {
protected:
    Vrv32i_decoder* dut;

    void SetUp() override {
        dut = new Vrv32i_decoder;
    }

    void TearDown() override {
        delete dut;
    }
};

// Basic test
TEST_F(DecoderTestVerilator, BasicADDI) {
    dut->instr = 0x00A58513;  // ADDI x10, x11, 10
    dut->eval();
    EXPECT_EQ(dut->rs1, 11);
    EXPECT_EQ(dut->rd, 10);
    EXPECT_EQ(dut->imm, 10);
    EXPECT_EQ(dut->alu_op, 0);
    EXPECT_TRUE(dut->reg_write);
    EXPECT_TRUE(dut->alu_src);
    EXPECT_FALSE(dut->mem_read);
    EXPECT_FALSE(dut->mem_write);
    EXPECT_FALSE(dut->branch);
    EXPECT_FALSE(dut->jump);
}

// R-type ADD
TEST_F(DecoderTestVerilator, RTypeADD) {
    dut->instr = 0x00B50533;  // ADD x10, x10, x11
    dut->eval();
    EXPECT_EQ(dut->rs1, 10);
    EXPECT_EQ(dut->rs2, 11);
    EXPECT_EQ(dut->rd, 10);
    EXPECT_EQ(dut->alu_op, 0);
    EXPECT_TRUE(dut->reg_write);
    EXPECT_FALSE(dut->alu_src);
    EXPECT_FALSE(dut->mem_read);
    EXPECT_FALSE(dut->mem_write);
    EXPECT_FALSE(dut->branch);
    EXPECT_FALSE(dut->jump);
}

// LW
TEST_F(DecoderTestVerilator, LW) {
    dut->instr = 0x00052503;  // LW x10, 0(x10)
    dut->eval();
    EXPECT_EQ(dut->rs1, 10);
    EXPECT_EQ(dut->rd, 10);
    EXPECT_EQ(dut->imm, 0);
    EXPECT_TRUE(dut->mem_read);
    EXPECT_TRUE(dut->mem_to_reg);
    EXPECT_TRUE(dut->reg_write);
    EXPECT_TRUE(dut->alu_src);
    EXPECT_EQ(dut->alu_op, 0);
}

// SW
TEST_F(DecoderTestVerilator, SW) {
    dut->instr = 0x00B52023;  // SW x11, 0(x10)
    dut->eval();
    EXPECT_EQ(dut->rs1, 10);
    EXPECT_EQ(dut->rs2, 11);
    EXPECT_EQ(dut->imm, 0);
    EXPECT_TRUE(dut->mem_write);
    EXPECT_FALSE(dut->reg_write);
    EXPECT_TRUE(dut->alu_src);
    EXPECT_EQ(dut->alu_op, 0);
}

// BEQ
TEST_F(DecoderTestVerilator, BEQ) {
    dut->instr = 0x00B50463;  // BEQ x10, x11, 8
    dut->eval();
    EXPECT_EQ(dut->rs1, 10);
    EXPECT_EQ(dut->rs2, 11);
    EXPECT_EQ(dut->imm, 8);
    EXPECT_TRUE(dut->branch);
    EXPECT_FALSE(dut->branch_type);
    EXPECT_FALSE(dut->reg_write);
    EXPECT_FALSE(dut->alu_src);
    EXPECT_EQ(dut->alu_op, 1);
}

// JAL
TEST_F(DecoderTestVerilator, JAL) {
    dut->instr = 0x008000EF;  // JAL x1, 8
    dut->eval();
    EXPECT_EQ(dut->rd, 1);
    EXPECT_EQ(dut->imm, 8);
    EXPECT_TRUE(dut->jump);
    EXPECT_TRUE(dut->reg_write);
    EXPECT_TRUE(dut->alu_src);
    EXPECT_EQ(dut->alu_op, 0);
}

// Random tests
TEST_F(DecoderTestVerilator, RandomInstructions) {
    for (int i = 0; i < 100; ++i) {
        // Generate random valid RV32I instructions
        uint32_t instr = (rand() % 6 + 1) * 0x10; // Basic opcodes
        instr |= (rand() & 0x1F) << 7; // rd
        instr |= (rand() & 0x1F) << 15; // rs1
        instr |= (rand() & 0x1F) << 20; // rs2
        dut->instr = instr;
        dut->eval();
        // Just check that it doesn't crash
        EXPECT_TRUE(true);
    }
}

int main(int argc, char **argv) {
    ::testing::InitGoogleTest(&argc, argv);
    return RUN_ALL_TESTS();
}